INSERT INTO quiz_question (id, word_bank_id, contextual_cloze, chinese_translation, correct_answer, distractor1, distractor2, distractor3, explanation_root_affix, explanation_mnemonic, created_at, updated_at) VALUES
('b56a5d22-7312-55d7-b147-3dd7acee78f6', '6d974953-9300-43a9-9c22-e0631653e3ae', 'I have ___ friends in Taipei.', '我在台北有一些朋友。', 'a few', 'much', 'little', 'every', 'a few 用於可數名詞，表示數量不多的「一些」。', 'a few → 一些 (用於可數名詞)。', '2026-07-06 12:12:49', '2026-07-06 12:12:49'),
('026d3bb5-e778-57e8-aa8f-ddfdfda27af2', 'b00c3ecc-3937-4075-bc21-db04de555c30', 'The dermatologist recommended a special cream to treat the severe ___ on his face.', '皮膚科醫生建議使用一種特殊的乳霜來治療他臉上嚴重的粉刺。', 'acne', 'fever', 'asthma', 'migraine', '源自希臘語 akme，意為尖峰或高峰，引申為皮膚上突出的病變。', '想像臉上長出許多像「小尖峰」一樣的突起物 → acne (粉刺)。', '2026-07-06 17:14:47', '2026-07-06 17:14:47'),
('a0a79380-755e-527e-bfba-d2dd8388688e', '7c9538ea-162a-496f-b6e8-206517448dd6', 'The chef decided to ___ some salt to the soup to improve its flavor.', '主廚決定在湯中添加一些鹽以改善其風味。', 'add', 'remove', 'enjoy', 'prepare', 'add 源自拉丁語 ad (to) + dare (give)，字面意思是「給予某物」→ 添加。', '想像在數學中把數字加起來 (add numbers)，就是把東西湊在一起。', '2026-07-06 17:34:32', '2026-07-06 17:34:32'),
('5ed336aa-109e-54b7-8ae5-8b82e58f6742', 'e89b4376-129f-4d76-bd81-d567a6a5f029', 'I ___ grateful for all the support you have provided during my difficult times.', '我非常感激你在我困難時期所提供的所有支持。', 'am', 'do', 'have', 'make', 'am 用於表達主詞當下的情感或心理狀態。', '表達感激用 I am grateful。', '2026-07-06 20:31:52', '2026-07-06 20:31:52'),
('f6f4ab46-8b47-578e-9680-53256300ee8e', '1451b0e7-bbb4-411d-83a4-21bf71d6eb39', 'There is ___ insect on the wall.', '牆上有一隻昆蟲。', 'an', 'the', 'some', 'each', 'an 是不定冠詞，用於母音音素開頭的單字前。', 'insect 的 i 是母音 → 用 an。', '2026-07-06 14:06:25', '2026-07-06 14:06:25'),
('78e8b20b-fcca-5d79-893b-e456f0463e92', 'd6d65e48-2c59-48b9-aa19-a9427026aaa0', 'The basketball player had to leave the game early because he twisted his ___ during the final minute.', '這位籃球員在最後一分鐘扭傷了腳踝，不得不提前離開比賽。', 'ankle', 'elbow', 'finger', 'shoulder', 'ankle 為名詞，指連接小腿與腳掌的關節部位。', '想像穿襪子時，襪子的邊緣剛好套在腳踝 (ankle) 的位置。', '2026-07-06 21:24:05', '2026-07-06 21:24:05'),
('ea26b765-dea5-5a2b-9c1e-b3d0074ebe26', 'eb1f9a6d-a7d9-44e1-bbd3-cf0069cefa1f', 'If you are lost in the city, don''t be afraid to ___ a local for directions.', '如果你在城市裡迷路了，不要害怕向當地人問路。', 'ask', 'tell', 'call', 'meet', 'ask 為基本動詞，意為「詢問」或「請求」。', '在迷路時，需要向別人 ask (問) 路。', '2026-07-07 00:44:55', '2026-07-07 00:44:55'),
('03ad405a-b783-53f5-b856-f29ae167868e', 'eb91f72c-b879-4b59-bcf1-c2d5ed90a6e0', 'Please make sure to check the ___ in the email for the detailed schedule.', '請務必檢查電子郵件中的附件，以獲取詳細的行程表。', 'attachment', 'arrangement', 'assignment', 'appointment', 'attach (連接/黏貼) + -ment (名詞字尾)', '想像把東西 attach (黏貼) 在文件上，加上 -ment 就變成了附件 (attachment)。', '2026-07-07 02:03:32', '2026-07-07 02:03:32'),
('fba79c5a-06ba-56a6-bbea-ffa76ca51b6a', '5d676716-1a75-4f0b-9c21-83d3b89581f7', 'The ocean looks very ___ under the bright sun.', '在明亮的陽光下，大海看起來非常藍。', 'blue', 'red', 'green', 'yellow', 'blue 為基礎單字，在此作為形容詞，表示 藍色的', '大海的顏色是 blue', '2026-07-07 04:51:18', '2026-07-07 04:51:18'),
('3a8d1eec-75f1-578e-be0f-6888262b39a2', 'c759c97e-0e01-42c6-b9dd-f44adb677775', 'The main ___ in this movie is very brave.', '這部電影的主角非常勇敢。', 'character', 'place', 'color', 'song', '名詞，指故事中的角色或人的性格。', 'Character 角色 → 想像 Actor 演員在演 Character 角色。', '2026-07-07 03:13:03', '2026-07-07 03:13:03'),
('51e3c542-3f81-57c9-a4f3-3941ae6daf5e', '94bd93b6-be24-465f-ae32-3f659fa84c59', 'We can use a ___ to see the weather for next week.', '我們可以使用圖表來查看下週的天氣。', 'chart', 'song', 'book', 'gift', 'chart 為名詞，表示圖表；亦可作為動詞，表示繪製圖表。', '想像在紙上畫(chart)一個圖表來觀察變化。', '2026-07-07 03:16:51', '2026-07-07 03:16:51'),
('e872d231-6514-50f2-abc8-0a918290153a', '75477c09-4129-4214-8c0f-d4b6a737b790', 'Be careful! Walking alone in this dark forest is ___.', '小心！獨自在這片黑暗的森林裡走路是很危險的。', 'dangerous', 'hungry', 'sleepy', 'noisy', 'danger (危險) 加上 -ous (形容詞字尾) 表示充滿危險的', 'danger (危險) + ous (充滿) → dangerous (危險的)', '2026-07-07 02:43:23', '2026-07-07 02:43:23'),
('f36aa05d-6c6b-515c-84f7-deeb5b82f05a', '4f5fcbd7-9d9a-4d43-9ed1-cd6dbb50743d', 'Can you tell the ___ between these two brothers?', '你能看出這兩兄弟之間的差別嗎？', 'difference', 'distance', 'color', 'weather', 'diff- 表示『不同』(different)。', 'difference 是名詞，表示兩者之間的『差別』。', '2026-07-07 03:59:27', '2026-07-07 03:59:27'),
('0e89197f-8f5c-5c07-bb78-a2edf7c82942', '4be7bf31-a497-41e6-8038-9a3a1ea21de6', 'I have a good ___ that everything will be okay.', '我有一種很好的感覺，一切都會好起來的。', 'feeling', 'sound', 'color', 'dream', 'feel (感覺) + ing (名詞字尾) → 感覺', '記住 feel 是「感覺」這個動作，加上 ing 就可以變成「一種感覺」這個名詞。', '2026-07-07 05:24:55', '2026-07-07 05:24:55'),
('f2d53b7a-92ed-57ba-ae7f-17cd6519b18a', 'c71bd206-4042-406c-8bc2-46572ad87585', 'The temperature rose ___ 30 degrees, reaching a record high.', '氣溫上升到了30度，創下歷史新高。', 'to', 'by', 'at', 'in', '表示方向、目的地或對象的介系詞。', 'to → 到 (達到某個點)', '2026-07-05 10:27:51', '2026-07-05 10:27:51');
